public class Action<T, V, K> extends Triple<T, V, K> {
    public Action(T v1, V v2, K v3) {
        super(v1, v2, v3);
    }

    public double calculate() {
        Stack<Double> stack = new Stack<>();

        String[] operands = v1.toString().split(" ");
        for (String operand : operands) {
            if (isNumber(operand)) {
                stack.push(Double.parseDouble(operand));
            } else {
                double operand2 = stack.pop();
                double operand1 = stack.pop();
                double result = performOperation(operand, operand1, operand2);
                stack.push(result);
            }
        }

        return stack.pop();
    }

    private boolean isNumber(String str) {
        try {
            Double.parseDouble(str);
            return true;
        } catch (NumberFormatException e) {
            return false;
        }
    }

    private double performOperation(String operator, double operand1, double operand2) {
        switch (operator) {
            case "+":
                return operand1 + operand2;
            case "-":
                return operand1 - operand2;
            case "*":
                return operand1 * operand2;
            case "/":
                return operand1 / operand2;
            default:
                throw new IllegalArgumentException("Неверный оператор");
        }
    }

