class Claw {
    float x, y;  // 钩爪的位置
    float length;  // 钩爪绳子的长度
    boolean isDropping;  // 钩爪是否在下落
    float velocity;  // 钩爪的速度
    float acceleration;  // 加速度
    float initialY;  // 钩爪的初始Y坐标
    boolean isSwinging;  // 钩爪是否在摇摆
    boolean isRetracting;  // 钩爪是否在回收
    float retractSpeed = 2; // 固定的收回速度

    Claw() {
        this.x = width / 2;
        this.initialY = 0;
        this.y = this.initialY;
        this.length = 50;
        this.isDropping = false;
        this.velocity = 0;
        this.acceleration = 0.05; // 初始加速度
        this.isSwinging = true;
    }

    void update() {
        if (isSwinging) {
            // 钩爪左右摆动
            if (x > width || x < 0) {
                direction *= -1;
            }
            x += speed * direction;
        }

        if (isDropping) {
            velocity += acceleration;
            y += velocity;

            // 当钩爪下落到屏幕五分之三的位置时开始减速
            if (y >= height * 3 / 5 && acceleration > 0) {
                acceleration -= 0.01;  // 逐渐减小加速度
            }

            // 当钩爪下落到屏幕十分之一的位置时停止
            if (y >= height * 9 / 10) {
                isDropping = false;
                isRetracting = true; // 开始回收钩爪
            }
        }
         if (isRetracting) {
            y -= retractSpeed; // 使用固定速度回收钩爪

            if (y <= initialY) { // 检查是否回到了初始位置
                y = initialY;
                isRetracting = false;
                isSwinging = true; // 重置为摇摆状态
            }
        }
    }

   void display() {
        stroke(0);
        line(x, initialY, x, y); // 绘制钩爪绳子
        image(clawImage, x - (clawImage.width - 30), y, clawImage.width , clawImage.height ); // 绘制钩爪头部，放大5倍
    }

    void drop() {
        if (!isDropping && isSwinging) {
            isDropping = true;
            isSwinging = false;
            velocity = 0;
            acceleration = 0.05; // 重置加速度
        }
    }
}

void draw() {
    image(backgroundImage, 0, 0, backgroundImage.width / 2, backgroundImage.height / 2);
    claw.update();
    claw.display();

    // 绘制垃圾，使用生成的随机水平坐标
    image(batteryImage, batteryX, 460, batteryImage.width / 2, batteryImage.height / 2);
    image(plasticBagImage, plasticBagX, 490, plasticBagImage.width / 2, plasticBagImage.height / 2);
    image(plasticBottleImage, plasticBottleX, 470, plasticBottleImage.width / 2, plasticBottleImage.height / 2);

    // TODO: 显示垃圾并处理碰撞等
}

