def get_method_id(tx_hash, api_key):
    URL = 'https://api.bscscan.com/api'

    payload = {
    "module": "proxy",
    "action": "eth_getTransactionByHash",
    "txhash": tx_hash,
    "apikey": api_key
    }

    resp = requests.get(URL, params=payload)
