    if "result" in response_data:
        tx_data = response_data["result"]
        if "input" in tx_data:
            input_data = tx_data["input"]
            method_id = input_data[:10] if input_data.startswith("0x") else None
        else:
            method_id = None
    else:
        method_id = None

    return method_id


