@RestController
@RequestMapping(“/current-analysis”)
public class CurrentAnalysisController {

    @Autowired
    private CurrentDataService currentDataService;

    @GetMapping(“/{inverterId}”)
    public CurrentAnalysisResult analyzeCurrent(@PathVariable Long inverterId,
                                                @RequestParam String dataType,
                                                @RequestParam String timeRange) {
        // 设定分析参数
        // 获取选定时间范围内的支路电流数据
        List<Double> currentData = currentDataService.getCurrentData(inverterId, dataType, timeRange);

        // 统计支路电流为零的次数，并计算零系数
        double zeroCount = currentData.stream().filter(current -> current == 0).count();
        double zeroFactor = zeroCount / currentData.size();

        // 计算支路电流的平均值，并判断每个支路电流是否低于平均值
        double averageCurrent = currentData.stream().mapToDouble(Double::doubleValue).average().orElse(0.0);
        long belowAverageCount = currentData.stream().filter(current -> current < averageCurrent).count();
        double lowFactor = belowAverageCount / currentData.size();

        return new CurrentAnalysisResult(zeroFactor, lowFactor);
    }
}

