@RestController
@RequestMapping(“/current-comparison”)
public class CurrentComparisonController {

    @Autowired
    private CurrentDataService currentDataService;

    @GetMapping(“/{inverterId}”)
    public List<Double> compareCurrent(@PathVariable Long inverterId) {
        // 获取逆变器支路电流数据
        List<Double> currentData = currentDataService.getCurrentData(inverterId, “daily”, “2021-09-01”);

        // 支路电流对比逻辑
        List<Double> comparisonResults = new ArrayList<>();
        double maxCurrent = currentData.stream().max(Double::compareTo).orElse(0.0);
        for (Double current : currentData) {
            double comparisonRatio = current / maxCurrent;
            comparisonResults.add(comparisonRatio);
        }

        return comparisonResults;
    }
}


