@RestController
@RequestMapping(“/power-generation”)
public class PowerGenerationController {

    @Autowired
    private PowerGenerationService powerGenerationService;

    @GetMapping(“/{inverterId}”)
    public String analyzeGeneration(@PathVariable Long inverterId) {
        // 计算逆变器发电量
        double generation = powerGenerationService.calculateGeneration(inverterId, “09:00”, “15:00”);

        // 计算逆变器等价发电小时平均值
        double averageEquivalentHours = powerGenerationService.calculateAverageEquivalentHours();

        // 根据逆变器运行水平返回结果
        if (generation > averageEquivalentHours) {
            return “正常”;
        } else if (generation > averageEquivalentHours * 0.85) {
            return “稍差”;
        } else if (generation > averageEquivalentHours * 0.75) {
            return “较差”;
        } else {
            return “极差”;
        }
    }
}

@Service
public class PowerGenerationServiceImpl implements PowerGenerationService {

    @Autowired
    private PowerGenerationRepository powerGenerationRepository;

    @Override
    public double calculateGeneration(Long inverterId, String startTime, String endTime) {
        // 根据逆变器ID、起始时间和结束时间计算逆变器发电量

        return powerGenerationRepository.calculateGeneration(inverterId, startTime, endTime);
    }

    @Override
    public double calculateAverageEquivalentHours() {
        // 计算逆变器等价发电小时平均值

        return powerGenerationRepository.calculateAverageEquivalentHours();
    }
}

@Repository
public class PowerGenerationRepository {

    @Autowired
    private JdbcTemplate jdbcTemplate;

    public double calculateGeneration(Long inverterId, String startTime, String endTime) {
        // 根据逆变器ID、起始时间和结束时间从数据库中查询发电数据，并进行计算

        // 例子：
        String sql = “SELECT SUM(generation) FROM power_generation WHERE inverter_id = ? AND time BETWEEN ? AND ?”;
        return jdbcTemplate.queryForObject(sql, Double.class, inverterId, startTime, endTime);
    }

    public double calculateAverageEquivalentHours() {
        // 从数据库中查询所有逆变器的等价发电小时数据，并计算平均值

        // 例子：
        String sql = “SELECT AVG(equivalent_hours) FROM power_generation”;
        return jdbcTemplate.queryForObject(sql, Double.class);
    }
}
