function isValidURL(url) {
  // Basic URL format check (you might want to use a more sophisticated check)
  const urlPattern =
    /^(https?:\/\/)?(www\.)?[a-zA-Z0-9.-]+\.[a-zA-Z]{2,6}(\/\S*)?$/;
  return urlPattern.test(url);
}

