// Like a news article
app.post("/news/like/:id", async (req, res) => {
  const { id } = req.params;
  const { loggedInUsername } = req.body;

  try {
    const news = await News.findById(id);

    if (!news) {
      return res.status(404).json({ error: "News article not found" });
    }

    const user = await User.findOne({ username: loggedInUsername });

    if (!user) {
      return res.status(404).json({ error: "User not found" });
    }

    if (user.likedNews.includes(id)) {
      return res
        .status(400)
        .json({ error: "User has already liked this article" });
    }

    if (user.dislikedNews.includes(id)) {
      // Remove from dislikedNews array
      user.dislikedNews.pull(id);
      await user.save();
      news.dislikes -= 1;
    }

    user.likedNews.push(id);
    await user.save();
    news.likes += 1;
    await news.save();

    res.status(200).json({ message: "News article liked successfully" });
  } catch (error) {
    console.error(error);
