app.post("/news/dislike/:id", async (req, res) => {
  const { id } = req.params;
  const { loggedInUsername } = req.body;

  try {
    const news = await News.findById(id);

    if (!news) {
      return res.status(404).json({ error: "News article not found" });
    }

    const user = await User.findOne({ username: loggedInUsername });

    if (!user) {
      return res.status(404).json({ error: "User not found" });
    }

    if (user.dislikedNews.includes(id)) {
      return res
        .status(400)
        .json({ error: "User has already disliked this article" });
    }

    if (user.likedNews.includes(id)) {
      // Remove from likedNews array
      user.likedNews.pull(id);
      await user.save();
      news.likes -= 1;
    }

    user.dislikedNews.push(id);
    await user.save();
    news.dislikes += 1;
    await news.save();

    res.status(200).json({ message: "News article disliked successfully" });
  } catch (error) {
    console.error(error);
    res.status(500).json({ error: "An error occurred" });
  }
});

