    event GameEnded(uint256 indexed gameId, address indexed activePLayer, address otherPlayer);
    event GameCancelled(uint256 indexed gameId, address cancelled);
    event RequestId(bytes32 requestId);
    event RandomWordGenerated(string indexed word);
    event FirstLetter(uint256 indexed gameId, string indexed firstLetter);
    event LetterSuggested(uint256 indexed gameId, address indexed player1, address indexed player2, string letterToGuess);
    event LetterWin(uint256 indexed gameId,address indexed player1, address indexed player2, string letterWin);
    event WordGuessed(uint256 indexed gameId, address activePlayer, address otherPlayer, string wordGuess);
    event WordWin(uint256 indexed gameId, address activePlayer, address otherPlayer, string wordFound);
    event PlayerSwitched(uint256 gameId, address indexed player1, address indexed player2);
    event BalanceDeposited(address indexed player, uint256 amount);
    event BalanceWithdrawn(address indexed player, uint256 amount);
    event PotWon(uint256 indexed gameId, address activePlayer, uint256 currentPot);

     constructor(uint64 subscriptionId) VRFConsumerBaseV2(vrfCoordinator) {
