    function withdraw(uint256 _amount, uint256 _gameId) public payable finished {
        Game storage game = games[_gameId];
        address player = msg.sender;
        require(game.player1 == player || game.player2 == player, "Vous n etes pas un joueur dans ce jeu");
        require(gameBalances[_gameId][player] > 0, "Vous n avez pas de solde a retirer");
