export const drawRoundedRect = (
  ctx: CanvasRenderingContext2D,
  x: number,
  y: number,
  width: number,
  height: number,
  radius: number,
): void => {
  ctx.beginPath();
  ctx.moveTo(x + radius, y + 1);
  ctx.lineTo(x + width - radius, y + 1);
  ctx.lineTo(x + width - radius, y + height - 1);
  ctx.lineTo(x + radius, y + height - 1);
  ctx.arcTo(x, y + height - 1, x, y + height - radius - 1, radius);
  ctx.lineTo(x, y + radius + 1);
  ctx.arcTo(x, y + 1, x + radius, y + 1, radius);
  ctx.closePath();
};

