class RandomAffineTransform(TransformBase):
    # “”“随机放射变换”“”
    def init(self, degrees, translate=None, scale=None, shear=None):
        super().init()
        self.degrees = degrees  # 旋转角度范围
        self.translate = translate  # 平移范围
        self.scale = scale  # 缩放范围
        self.shear = shear  # 倾斜范围

    def roll(self):
        # “”“随机生成放射变换参数”“”
        angle = np.random.uniform(-self.degrees, self.degrees)
        if self.translate is not None:
            tx = np.random.uniform(-self.translate[0], self.translate[0])
            ty = np.random.uniform(-self.translate[1], self.translate[1])
        else:
            tx = 0
            ty = 0
        if self.scale is not None:
            scale = np.random.uniform(self.scale[0], self.scale[1])
        else:
            scale = 1.0
        if self.shear is not None:
            shear = np.random.uniform(-self.shear, self.shear)
        else:
            shear = 0

        return angle, tx, ty, scale, shear

    def transform_image(self, image, angle, tx, ty, scale, shear):
        # “”“应用放射变换到图像”“”
        if torch.is_tensor(image):
            affine_params = F.affine_params(angle, translate=(tx, ty), scale=scale, shear=shear)
            image = F.affine(image, **affine_params)
        else:
            (h, w) = image.shape[:2]
            m = cv.getRotationMatrix2D((w // 2, h // 2), angle, scale)
            image = cv.warpAffine(image, m, (w, h))
        return image
