        controllerOVPPoseBehaviour = FireExtinguisherOVP.GetComponent<SteamVR_Behaviour_Pose>();
        controllerOUPoseBehaviour = FireExtinguisherOU.GetComponent<SteamVR_Behaviour_Pose>();

