                RestoreValuesBody();
                RestoreValuesTip();
                OffAllFireExtinguishers();
                FireExtinguisherOVP.gameObject.SetActive(true);
                controllerOVPPoseBehaviour.poseAction = controllerBasePoseAction;
                controllerOVPPoseTipBehaviour.poseAction = controllerBasePoseTipAction;

                publisher.Publish(new ActivationCurrentFireExtinguisherMessage(FireExtinguisherOVP.gameObject.GetComponent<FireExtinguisher>()));
                break;
        }
    }
    private void RestoreValuesBody()
    {
        controllerOPPoseBehaviour.poseAction = controllerOPPoseAction;
        controllerOUPoseBehaviour.poseAction = controllerOUPoseAction;
        controllerOVPPoseBehaviour.poseAction = controllerOVPPoseAction;
    }
    private void RestoreValuesTip()
    {
        controllerOPPoseTipBehaviour.poseAction = controllerOPPoseTipAction;
        controllerOUPoseTipBehaviour.poseAction = controllerOUPoseTipAction;
        controllerOVPPoseTipBehaviour.poseAction = controllerOVPPoseTipAction;
    }
    private void OffAllFireExtinguishers()
    {
        FireExtinguisherOP.gameObject.SetActive(false);
        FireExtinguisherOU.gameObject.SetActive(false);
        FireExtinguisherOVP.gameObject.SetActive(false);
    }
    private void OnEnable()
    {
        subscriber.UnSudscribe<SwitchFireExtinguisherMessage>(SwitchFireExtinguisher);
    }
}
