          // Set map bounds to encompass marker and polyline
          const bounds = new google.maps.LatLngBounds(); // Use google.maps here
          bounds.extend(markerPosition);
          bounds.extend(polyline.getPath().getAt(1));
          map.fitBounds(bounds);
        }
