function [Y0, Y, TN, branch_new,bus,nb_0,nl_0] = Y0Y(base, bus, branch)
%% 调用IEEE39节点，进行节点数、支路数赋予
if nargin < 3
    mpc     = base;               %使用IEEE39标准节点
    baseMVA = mpc.baseMVA;
    bus     = mpc.bus;
    branch  = mpc.branch;
    TN=branch;
else
    mpc     = base;               %使用自定义的节点编号
    baseMVA = mpc.baseMVA;
    bus     = bus;
    branch  = branch;
    TN=branch;
end
%% 原始数据
nb = size(bus, 1);          %% 节点数
nl = size(branch, 1);       %% 支路数
nl_0 = size(branch, 1);     %% 原始支路数
nb_0 = size(bus, 1);        %% 原始节点数
%% 为了求解Y0，将地节点作为第nb+1个节点，调整bus矩阵
%% 同时支路电纳值b会产生新的对地支路，需要对branch矩阵进行扩充
nb = nb + 1;                                         %%新增对地节点
Bc = 1 .* branch(:, 5) / 2;                          %%存储支路对地电纳值，无需标幺化操作
for k = 1:nl_0                                       %%扩充branch矩阵
    if branch(k, 5) > 0
       branch(nl+1, 1) = branch(k, 1);
       branch(nl+2, 1) = branch(k, 2);
       branch(nl+1, 2) = nb;
       branch(nl+2, 2) = nb;
       branch(nl+1, 4) = -1 / Bc(k);                 %%统一变为电抗形式保存，方便求和
       branch(nl+2, 4) = -1 / Bc(k);
       nl = nl + 2;                                 
    end                                             
end 

%% 考虑节点并联电纳对导纳矩阵的影响
%% 每有一个节点并联电纳相当于增加一条和nb+1号节点间的支路
Bsh = bus(:, 6) / baseMVA;                          %%计算标幺化节点并联电纳值
for m = 1:nb_0                                      %%扩充branch矩阵
    if Bsh(m) > 0
        branch(nl+1, 1) = m;
        branch(nl+1, 2) = nb;
        branch(nl+1, 4) = -1 / Bsh(m);
        nl = nl + 1;                                 
    end
end

%% 计算每一条支路的影响并叠加
Yl=zeros(nl,1);                                               %%支路贡献
for t=1:nl
    if branch(t,9)==0                                         %%非变压器支路
        Yl(t) = 1 / (branch(t, 3) + 1j * branch(t, 4));       %%每一条支路会影响四个元素
        Yff(t)= Yl(t);
        Ytt(t) = Yl(t);     
        Yft(t) = -Yl(t);
        Ytf(t) = -Yl(t);
    else                                                      %%变压器支路
        Yl(t) = 1 / (branch(t, 3) + 1j * branch(t, 4));
        Yff(t) = Yl(t)/(branch(t,9)^2);
        Ytt(t) = Yl(t);
        Yft(t) = -Yl(t)/(branch(t,9));
        Ytf(t) = -Yl(t)/(branch(t,9));
    end
end  
